window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q07"]=window.__LIBQ["tien-nghich"]["q07"]||{};window.__LIBQ["tien-nghich"]["q07"]["factions"]={"updatedAt":"2026-07-06","count":116,"factions":[{"id":"la-thien","name":"La Thiên","cn":"","type":"tinh-vuc","typeLabel":"Tinh vực","diaBan":"La Thiên","nhanVatChinh":["Huyễn gia Lão Tổ"],"blurb":"Tinh vực nơi Huyễn gia Lão Tổ đang ở, được nhắc trong suy luận về việc cao thủ từ Liên Minh Tinh Vực khó vượt tới nếu thiếu La Thiên Thạch.","detail":"Huyễn gia Lão Tổ cho rằng Vương Lâm thuộc Liên Minh Tinh Vực; nếu sư tôn của Vương Lâm muốn vượt tới La Thiên thì sẽ gặp trở ngại vì La Thiên Thạch, và xung đột có thể bị nâng thành chuyện giữa hai tinh vực.","nguon":["@c0636"]},{"id":"thien-gia","name":"Thiên gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Thiên Huyễn Tinh","nhanVatChinh":["Thiên gia lão hữu"],"blurb":"Gia tộc trên Thiên Huyễn Tinh được Huyễn gia Lão Tổ cầu viện sau khi quyết giữ Liễu Mi.","detail":"Khi chịu áp lực từ kiếm khí của Vương Lâm và vẫn không muốn giao Liễu Mi, Huyễn gia Lão Tổ tản thần thức truyền khắp Thiên Huyễn Tinh, gọi Thiên gia lão hữu tới hỗ trợ.","nguon":["@c0636","@c0638","@c0665"]},{"id":"tuyet-vuc-quoc-faction","name":"Tuyết Vực quốc","cn":"","type":"tu-chan-quoc","typeLabel":"Tu chân quốc","diaBan":"Chu Tước Tinh","nhanVatChinh":["Tông chủ Tuyết Vực quốc","Hồng Điệp"],"blurb":"Tu chân quốc ở Chu Tước Tinh được nhắc lại như tiền lệ dùng phương pháp cưỡng ép nâng tu vi để hướng tới thăng cấp.","detail":"Trong lời giải thích cho Tôn Tích, Vương Lâm nhắc Tuyết Vực quốc từng muốn nâng lên Ngũ cấp tu chân quốc khi Hồng Điệp được Chu Tước quốc nhìn trúng, nên tông chủ dùng cách cưỡng ép nâng Hóa Thần lên Anh Biến, đổi lấy kết quả trước mắt nhưng dừng bước về sau.","nguon":["@c0637"]},{"id":"dong-lam-tinh-faction","name":"Đông Lâm Tinh","cn":"","type":"the-luc","typeLabel":"Thế lực tinh cầu","diaBan":"La Thiên Tinh Vực","nhanVatChinh":[],"blurb":"Đông Lâm Tinh là thế lực có danh vọng lớn trong La Thiên Tinh Vực. Chương này nhắc nơi đây qua các dấu hiệu liên hệ với Hứa gia trên Thiên Huyễn Tinh.","detail":"Hứa gia tuy đứng thứ ba trong ba đại gia tộc Thiên Huyễn Tinh nhưng được Thiên gia và Huyễn gia kiêng kị vì nhiều manh mối cho thấy có quan hệ với Đông Lâm Tinh. Chương chưa cho thấy Đông Lâm Tinh trực tiếp nhập cuộc.","nguon":["@c0638"]},{"id":"loi-tien-gioi-faction","name":"Lôi Tiên giới","cn":"","type":"gioi","typeLabel":"Giới","diaBan":"La Thiên Tinh Vực","nhanVatChinh":[],"blurb":"Lôi Tiên giới là thế lực hoặc giới vực được nhắc trong quan hệ với La Thiên Tinh Vực và Lôi Tiên Điện.","detail":"Tộc nhân Huyễn gia được nêu là người ở hạ giới của Lôi Tiên giới tại La Thiên Tinh Vực, nên đặc biệt kính sợ Lôi thần thông và biểu tượng Lôi Thú trong trận công kích Huyễn gia.","nguon":["@c0639"]},{"id":"co-toc","name":"Cổ Tộc","cn":"","type":"chung-toc","typeLabel":"Chủng tộc","diaBan":"Không rõ","nhanVatChinh":["Tán Ma"],"blurb":"Cổ Tộc được nhắc qua ngôn ngữ mà Tán Ma dùng để phát động thủ đoạn Cổ Ma. Ngôn ngữ này gắn với lời gọi Cổ Ma và việc rút tinh hồn Thiên Huyễn Tinh.","detail":"Trong trận tại Thiên Huyễn Tinh, Tán Ma dùng ngôn ngữ Cổ Tộc khi gọi Cổ Ma và thi triển thủ đoạn rút tinh hồn. Dữ kiện này đặt Cổ Tộc như nền tảng ngôn ngữ và nguồn gốc thuật pháp liên quan đến Cổ Ma.","nguon":["@c0641"]},{"id":"dai-tan-quoc","name":"Đại Tần quốc","cn":"","aliases":["Đại Tần"],"type":"quoc-gia","typeLabel":"Quốc gia","diaBan":"Nhiễm Vân tinh","nhanVatChinh":["Vương Lâm","Vương Bình"],"blurb":"Một trong ba đại đế quốc trên Nhiễm Vân tinh. Kỳ Thủy thành là một phó đô phồn hoa của quốc gia này.","detail":"Đại Tần quốc được giới thiệu là một trong ba đại đế quốc của Nhiễm Vân tinh. Kỳ Thủy thành thuộc Đại Tần quốc, có mức phồn hoa gần với kinh đô và trở thành nơi Vương Lâm quyết định đưa Vương Bình tới định cư.","nguon":["@c0648"]},{"id":"chi-nhanh-ton-gia-ky-thuy-thanh","name":"Chi nhánh Tôn gia Kỳ Thủy thành","cn":"","type":"chi-nhanh","typeLabel":"Chi nhánh gia tộc","diaBan":"Kỳ Thủy thành","nhanVatChinh":["Lão nhân mặt đỏ","Trưởng lão áo xanh","Trưởng lão Tôn gia thứ ba","Tu sĩ Nguyên Anh hậu kỳ Tôn gia","Tôn Khải Minh"],"blurb":"Chi nhánh Tôn gia tại Kỳ Thủy thành, nơi ba trưởng lão Hóa Thần xử lý vụ tửu lâu. Sau khi đánh giá người gây chuyện có thể là Anh Biến, họ báo về dòng họ và nghênh đón Tôn Khải Minh tới điều tra.","detail":"Chi nhánh này triệu tập những người liên quan vụ tửu lâu, thẩm vấn Thanh Nghi và các tu sĩ Tôn gia, rồi báo lên dòng họ để điều tu sĩ Anh Biến tới Kỳ Thủy. Ba ngày sau, toàn bộ chi nhánh ra nghênh đón Tôn Khải Minh khi hắn vào thành.","nguon":["@c0650"]},{"id":"van-gia","name":"Vân gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Vân Hải tinh","nhanVatChinh":["Vân Vô Phong","Trưởng lão thương đội Vân gia"],"blurb":"Đại gia tộc trên Vân Hải tinh, được gọi là đệ nhất gia tộc ở nơi này và mạnh hơn Huyễn gia năm đó. Thân phận Vân gia khiến Vân Vô Phong dù không có tu vi vẫn được nhiều gia tộc tu chân ở Nhiễm Vân tinh nể mặt.","detail":"Vân gia là thế lực lớn trên Vân Hải tinh thuộc La Thiên Bắc Vực. Vân Vô Phong là tộc nhân ngoại tộc của gia tộc này, tư chất kém không thể tu đạo nhưng nhờ xuất thân Vân gia nên khi ở Nhiễm Vân tinh vẫn được đối đãi kiêng dè; trưởng lão thương đội Vân gia từng cảnh báo hắn tuyệt đối không trêu chọc Hứa Mộc.","nguon":["@c0651"]},{"id":"thien-hanh-phai","name":"Thiên Hành phái","cn":"","type":"giao-phai","typeLabel":"Giáo phái phàm nhân","diaBan":"Bắc bộ Nhiễm Vân tinh","nhanVatChinh":[],"blurb":"Giáo phái xuất hiện trong thế giới phàm nhân ở Bắc bộ Nhiễm Vân tinh sau ba năm Vương Bình rời Kỳ Thủy Thành. Giáo phái này phát triển mạnh, được đồn có thủ lĩnh như tiên nhân và bên cạnh luôn có một nữ nhân.","detail":"Thiên Hành phái chỉ lưu truyền trong phàm nhân nhưng lan rộng nhanh ở Bắc bộ Nhiễm Vân tinh. Sự xuất hiện của giáo phái được đặt sau mốc Vương Bình rời đi cùng Thanh Nghi, với lời đồn về một thủ lĩnh giống tiên nhân và một nữ nhân luôn đi cạnh.","nguon":["@c0651"]},{"id":"thien-hanh-de-quoc","name":"Thiên Hành đế quốc","cn":"","type":"quoc-gia","typeLabel":"Quốc gia","diaBan":"Nhiễm Vân Tinh","nhanVatChinh":["Vương Bình","Thanh Nghi"],"blurb":"Thiên Hành đế quốc là quốc gia mới thay thế Đế Sơn quốc sau khi Thiên Hành phái phản kích và đoạt binh quyền. Vương Bình mặc long bào đứng ở vị trí quân chủ, Thanh Nghi ở bên cạnh.","detail":"Sau khi Đế Sơn quốc toàn lực chèn ép Thiên Hành phái, mạng lưới giáo chúng trong triều và quân đội khiến cục diện đảo chiều rất nhanh. Đế Sơn quốc bị thay thế bởi Thiên Hành đế quốc; về sau quốc gia này bị Đại Tần và Trần Vân xé minh ước tấn công, mở rộng chiến tranh giữa ba nước.","nguon":["@c0652"]},{"id":"de-son-quoc","name":"Đế Sơn quốc","cn":"","type":"quoc-gia","typeLabel":"Quốc gia","diaBan":"Bắc bộ Nhiễm Vân Tinh","nhanVatChinh":["Vương Bình"],"blurb":"Đế Sơn quốc là một trong ba đại đế quốc trên Nhiễm Vân Tinh. Sau khi toàn lực chèn ép Thiên Hành phái, quốc gia này bị Thiên Hành phái đoạt binh quyền và thay thế bằng Thiên Hành đế quốc.","detail":"Đế Sơn quốc từng là thế lực thế tục lớn ở bắc bộ Nhiễm Vân Tinh. Khi Thiên Hành phái lan rộng tới mức bao phủ ba đại đế quốc, Đế Sơn quốc ra tay chèn ép và phái binh tiêu diệt, nhưng bị phản kích từ trong triều đình và quân đội, dẫn tới mất nước.","nguon":["@c0652"]},{"id":"tran-van","name":"Trần Vân","cn":"","type":"quoc-gia","typeLabel":"Quốc gia","diaBan":"Nhiễm Vân Tinh","nhanVatChinh":[],"blurb":"Trần Vân là một trong ba đại đế quốc trên Nhiễm Vân Tinh. Ban đầu nước này ký minh ước không xâm phạm với Thiên Hành đế quốc, sau đó cùng Đại Tần xé bỏ ước định và tấn công.","detail":"Sau biến cố Đế Sơn quốc, Trần Vân không lập tức hành động mà cùng Đại Tần liên hệ Thiên Hành phái để ký hiệp ước đồng minh. Năm thứ năm sau khi Thiên Hành đế quốc thành lập, Trần Vân cùng Đại Tần phá bỏ minh ước, khiến chiến tranh ba quốc gia bùng lên.","nguon":["@c0652"]},{"id":"thien-cuc-su-gia","name":"Thiên Cực sứ giả","cn":"","type":"chuc-vi","typeLabel":"Chức vị trong Lôi Tiên Điện","diaBan":"Lôi Tiên Điện","nhanVatChinh":[],"blurb":"Nhóm sứ giả cấp cao rất ít người trong Lôi Tiên Điện. Chương cho biết chỉ vài Thiên Cực sứ giả mới có thể nắm Ngân Giác lôi thú.","detail":"Khi nhìn thấy Ngân Giác lôi thú của Vương Lâm, Lôi Đạo Tử nhận ra giá trị cực hiếm của nó và liên hệ tới số rất ít Thiên Cực sứ giả trong Lôi Tiên Điện có thể sở hữu loại lôi thú này. Nhận thức ấy khiến hắn nổi tham niệm muốn giết Vương Lâm để đoạt thú vô chủ.","nguon":["@c0657"]},{"id":"dia-cap-su-gia-loi-tien-dien","name":"Địa cấp sứ giả Lôi Tiên Điện","cn":"","type":"chuc-vi","typeLabel":"Chức vị trong Lôi Tiên Điện","diaBan":"Lôi Tiên Điện","nhanVatChinh":[],"blurb":"Cấp sứ giả trong hệ thống Lôi Tiên Điện được Lôi Đạo Tử nhắc tới khi đánh giá lôi hệ thần thông của Vương Lâm. Hắn cho rằng loại thần thông ấy chỉ thấy trên người địa cấp sứ giả.","detail":"Dù ngoài miệng nói Vương Lâm giả mạo sứ giả, Lôi Đạo Tử vẫn nghi ngờ vì lôi hệ thần thông trước đó quá kinh người. Hắn so sánh nó với năng lực từng thấy trên thân địa cấp sứ giả Lôi Tiên Điện, khiến thân phận Hứa Mộc càng khó phân định trong mắt hắn.","nguon":["@c0657"]},{"id":"thien-thuy-cung","name":"Thiên Thủy Cung","cn":"","type":"tong-mon","typeLabel":"Thế lực tu chân","diaBan":"Ngũ Hành Tinh","nhanVatChinh":["Tử Tâm","Huyết Tổ"],"blurb":"Thiên Thủy Cung là thế lực trên Ngũ Hành Tinh từng có xích mích với Tử Tâm. Tử Tâm bị thế lực này truy sát trước khi được Huyết Tổ cứu.","detail":"Lai lịch của Tử Tâm cho biết nàng từng kết oán với Thiên Thủy Cung của Ngũ Hành Tinh. Huyết Tổ ra tay cứu nàng khỏi truy sát, từ đó nàng trở thành thị thiếp của hắn.","nguon":["@c0663"]},{"id":"ngu-hanh-tinh-faction","name":"Ngũ Hành Tinh","cn":"","type":"dia-ban","typeLabel":"Địa bàn thế lực","diaBan":"Không rõ","nhanVatChinh":["Tử Tâm"],"blurb":"Ngũ Hành Tinh được nhắc qua Thiên Thủy Cung trong lai lịch Tử Tâm. Đây là nơi gắn với thế lực từng truy sát nàng.","detail":"Trong chương này, Ngũ Hành Tinh xuất hiện như địa bàn của Thiên Thủy Cung. Việc Tử Tâm từng bị Thiên Thủy Cung truy sát là nguyên nhân khiến Huyết Tổ can dự và đưa nàng vào phạm vi thế lực của mình.","nguon":["@c0663"]},{"id":"huyet-to-the-luc","name":"Huyết Tổ thế lực","cn":"","type":"the-luc","typeLabel":"Thế lực cá nhân","diaBan":"Huyết Tinh và vùng phụ cận trong Liên Minh Tinh Vực","nhanVatChinh":["Huyết Tổ","Tử Tâm","Hai huyết nô của Huyết Tổ"],"blurb":"Huyết Tổ thế lực bao gồm phạm vi tinh cầu dưới ảnh hưởng của Huyết Tổ, Huyết Tinh và các huyết nô Vấn Đỉnh. Tử Tâm hoạt động trong phạm vi này khi điều tra tinh cầu chết dần.","detail":"Tiểu tinh cầu hoang dã nơi Tử Tâm điều tra thuộc phạm vi Huyết Tổ. Thế lực này có Huyết Tinh làm nơi truyền tống về, có huyết nô Vấn Đỉnh đi theo Tử Tâm và vẫn duy trì ảnh hưởng dù Huyết Tổ sau khi từ Yêu Linh Chi Địa trở về đã rời đi không rõ tung tích.","nguon":["@c0663"]},{"id":"loi-chi-ha-gioi","name":"Lôi Chi hạ giới","cn":"","type":"khac","typeLabel":"Đích đến chưa rõ","diaBan":"Không rõ","nhanVatChinh":["Thiên Ma Tán Nhân"],"blurb":"Lôi Chi hạ giới được Thiên Ma Tán Nhân nhắc tới sau khi rời Chu Tước Tinh. Đây là hướng hành động tiếp theo của sứ giả Thác Sâm.","detail":"Sau khi tái xuất với thân phận sứ giả của Thác Sâm, Thiên Ma Tán Nhân rời Chu Tước Tinh và nhắc tới Lôi Chi hạ giới. Chương chưa giải thích rõ bản chất nơi này, chỉ cho thấy nó liên quan tới tuyến hành động kế tiếp của hắn.","nguon":["@c0663"]},{"id":"huyen-gia","name":"Huyễn Gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu chân","diaBan":"Thiên Huyễn Tinh","nhanVatChinh":["Huyễn Phong Thần"],"blurb":"Gia tộc trên Thiên Huyễn Tinh bị Vương Lâm dùng thân phận sứ giả Lôi Tiên Điện gây áp lực.","detail":"Huyễn Gia dưới sự dẫn dắt của Huyễn Phong Thần ra nghênh tiếp Vương Lâm khi lôi thú giáng lâm Thiên Huyễn Tinh. Trước uy thế và danh nghĩa Lôi Tiên Điện, Huyễn Gia giao toàn bộ Thăng Tiên quả đã sưu tầm, đồng nghĩa bỏ cơ hội tiến vào Lôi Chi tiên giới sau trăm năm.","nguon":["@c0664"]},{"id":"cac-gia-toc-tu-chan","name":"Các gia tộc tu chân","cn":"","type":"gia-toc","typeLabel":"Nhóm gia tộc tu chân","diaBan":"La Thiên bắc vực","nhanVatChinh":["Vương Lâm"],"blurb":"Nhiều gia tộc tu chân giao Thăng Tiên quả cho Vương Lâm vì thân phận Sứ giả Lôi Tiên Điện.","detail":"Một số gia tộc nhỏ còn muốn phụ thuộc Vương Lâm, nhưng hắn từ chối vì lo thân phận bại lộ sẽ liên lụy họ.","nguon":["@c0666"]},{"id":"ngu-dai-chu-tinh","name":"Ngũ Đại Chủ Tinh","cn":"","type":"khu-vuc-the-luc","typeLabel":"Khu vực chủ tinh","diaBan":"La Thiên Bắc Vực","nhanVatChinh":[],"blurb":"Cụm chủ tinh trọng yếu ở La Thiên Bắc Vực, được nhắc khi Vọng Nguyệt lui về ngủ rất gần phạm vi này.","detail":"Sau khi dừng truy sát Vương Lâm ở ranh giới Nam-Bắc Vực, Vọng Nguyệt quay lại La Thiên Bắc Vực và chọn trạng thái ngủ thứ hai ở vị trí rất gần Ngũ Đại Chủ Tinh. Khoảng cách quá gần giữa dị thú khổng lồ này và khu vực chủ tinh khiến tu sĩ Bắc Vực bất an.","nguon":["@c0674"]},{"id":"tien-vuc-thoi-vien-co","name":"Tiên Vực thời viễn cổ","cn":"","type":"khac","typeLabel":"Nguồn gốc nghi vấn","diaBan":"Không rõ","nhanVatChinh":[],"blurb":"Nguồn gốc nghi vấn của Thiên Nghịch Châu trong suy nghĩ của Vương Lâm. Chương này chỉ nêu như một khả năng qua lời người phụ nữ trên tranh từng nói.","detail":"Khi ngũ hành Thiên Nghịch viên mãn, Vương Lâm nhớ lại lời người phụ nữ trên cuốn tranh rằng Hạt Châu Thiên Nghịch có thể đến từ Tiên Vực thời viễn cổ. Thông tin được giữ ở mức nghi vấn, chưa xác nhận lai lịch thật của bảo vật.","nguon":["@c0675"]},{"id":"thien-van-tinh","name":"Thiên Vận Tinh","cn":"","type":"dia-ban","typeLabel":"Địa bàn thế lực","diaBan":"Thiên Vận Tinh","nhanVatChinh":["Thiên Vận Tử"],"blurb":"Địa bàn gắn với Thiên Vận Tử, được nhắc như thứ có thể bị ông ta đánh đổi để cầu cơ duyên hiểu Đạo.","detail":"Trong suy nghĩ của Vương Lâm, cơ duyên hiểu Đạo trước cánh cửa thần bí quý đến mức người như Thiên Vận Tử có thể từ bỏ Thiên Vận Tinh, thần thông và pháp bảo để tranh lấy. Thiên Vận Tinh vì vậy được nhắc như căn cơ thế lực quan trọng của Thiên Vận Tử.","nguon":["@c0680"]},{"id":"gia-toc-than-cong","name":"Gia tộc Thân Công","cn":"","aliases":["Thân Công tộc"],"type":"gia-toc","typeLabel":"Gia tộc tu chân","diaBan":"Nam vực của La Thiên","nhanVatChinh":["Thân Công Hổ"],"blurb":"Gia tộc Thân Công là gia tộc tu chân ở nam vực La Thiên, xuất thân của Thân Công Hổ. Khi cầu dựa vào Vương Lâm, Thân Công Hổ nêu rõ thân phận người Thân Công tộc của mình.","detail":"Thân Công Hổ tự xưng là người của Thân Công tộc ở nam vực La Thiên, đồng thời là Nhị cấp sứ giả Lôi Tiên Điện và tu sĩ Dương Thật. Gia tộc này gắn với mạng lưới thế lực bản địa của hắn tại La Thiên.","nguon":["@c0681"]},{"id":"cac-gia-toc-tu-chan-le-thuoc-than-cong-ho","name":"Các gia tộc tu chân lệ thuộc Thân Công Hổ","cn":"","type":"lien-minh","typeLabel":"Thế lực phụ thuộc","diaBan":"La Thiên Tinh Vực","nhanVatChinh":["Thân Công Hổ"],"blurb":"Đây là nhóm gia tộc tu chân được Thân Công Hổ nói là lệ thuộc vào hắn. Hắn dùng nguồn lực này để chứng minh mình có thể thỏa mãn nhu cầu của Vương Lâm khi xin dựa vào.","detail":"Khi thuyết phục Vương Lâm, Thân Công Hổ nói bản thân có nhiều gia tộc tu chân lệ thuộc, có thể toàn lực đáp ứng yêu cầu của Vương Lâm. Thông tin này cho thấy hắn không chỉ có tu vi Dương Thật mà còn sở hữu mạng lưới thế lực tại La Thiên.","nguon":["@c0681"]},{"id":"tu-dai-tien-gioi-phong-vu-loi-dien","name":"Tứ đại tiên giới Phong, Vũ, Lôi, Điện","cn":"","type":"khac","typeLabel":"Hệ thống tiên giới","diaBan":"Liên thông Viễn Cổ Tiên Vực","nhanVatChinh":[],"blurb":"Tứ đại tiên giới Phong, Vũ, Lôi, Điện được nhắc như hệ thống thông đạo tiến vào Viễn Cổ Tiên Vực từ vô số năm trước. Lôi Tiên Giới là một phần trong hệ thống này.","detail":"Khi nói về Lôi Tiên Giới, Thân Công Hổ nhắc tới bốn tiên giới Phong, Vũ, Lôi, Điện như các thông đạo từng dẫn vào Viễn Cổ Tiên Vực. Chi tiết này đặt Lôi Tiên Giới trong bối cảnh rộng hơn của các tiên giới cổ xưa.","nguon":["@c0681","@c0788"]},{"id":"chien-gia","name":"Chiến gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Không rõ","nhanVatChinh":["Chiến Không Liệt"],"blurb":"Gia tộc của Chiến Không Liệt, được đặt trong thế đối đầu với Thân Công Hổ.","detail":"Thân Công Hổ vốn chán ghét những người tư chất cao của Chiến gia. Chiến Không Liệt mang họ Chiến, xuất hiện ở Lôi Trì và chuẩn bị giao chiến với Thân Công Hổ.","nguon":["@c0684"]},{"id":"truong-gia","name":"Trương gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu chân","diaBan":"Thanh Linh Tinh, Hoành Vân Phong","nhanVatChinh":["Trương Tân Hải"],"blurb":"Trương gia là gia tộc tu chân mạnh trên Thanh Linh Tinh, có nhiều tu sĩ Nguyên Anh nhất tại đây. Hoành Vân Phong là địa bàn trọng yếu và là nơi tộc nhân Nguyên Anh đại viên mãn thường bế quan tọa hóa trước khi hết thọ nguyên.","detail":"Trương gia nắm địa bàn quanh Hoành Vân Phong trên Thanh Linh Tinh. Trong bối cảnh tinh cầu này chỉ có tu sĩ cao nhất tới Nguyên Anh, Trương gia được xem là thế lực tu chân mạnh, đời này do Trương Tân Hải làm gia chủ; những tộc nhân Nguyên Anh đại viên mãn trước lúc thọ nguyên cạn thường lên Hoành Vân Phong tọa hóa.","nguon":["@c0686"]},{"id":"cac-gia-toc-tu-chan-tren-thanh-linh-tinh","name":"Các gia tộc tu chân trên Thanh Linh Tinh","cn":"","type":"the-luc-dia-phuong","typeLabel":"Thế lực địa phương","diaBan":"Thanh Linh Tinh","nhanVatChinh":["Vương Lâm","Trương Tân Hải"],"blurb":"Nhóm các gia tộc tu chân trên Thanh Linh Tinh, được Trương Tân Hải truyền đạt lệnh của Vương Lâm về việc thu oán khí phàm nhân.","detail":"Sau khi Vương Lâm tuyên bố Thanh Linh Tinh là tu chân tinh của mình, Trương Tân Hải để các gia tộc tu chân trên tinh cầu biết yêu cầu thu oán khí phàm nhân. Trong năm năm, các tu sĩ trên toàn tinh cầu bôn ba khắp phố phường để tích góp oán khí, nhưng tiến độ vẫn chưa đến bốn phần.","nguon":["@c0687"]},{"id":"thanh-linh-tinh","name":"Thanh Linh Tinh","cn":"","type":"cong-dong-tu-si","typeLabel":"Cộng đồng tu sĩ tinh cầu","diaBan":"Thanh Linh Tinh","nhanVatChinh":["Vương Lâm","Trương Tân Hải"],"blurb":"Cộng đồng tu sĩ trên Thanh Linh Tinh ngày càng kính sợ danh hiệu chủ nhân Hoành Vân Phong của Vương Lâm. Màn sương đen quanh nơi hắn bế quan trở thành vùng cấm đối với người tu chân trên tinh cầu.","detail":"Trong tám năm Vương Lâm ở Thanh Linh Tinh, hầu như chỉ Trương Tân Hải từng gặp hắn. Tu sĩ trên tinh cầu càng lúc càng biết rõ danh hiệu lão tổ Thanh Linh Tinh, đồng thời sợ hãi màn sương đen ngoài Hoành Vân Phong vì những kẻ liều lĩnh xông vào đều bị nuốt lấy.","nguon":["@c0688"]},{"id":"hai-gia-toc-tu-chan-tren-thanh-dan-tinh","name":"Hai gia tộc tu chân trên Thánh Đàn Tinh","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu chân","diaBan":"Thánh Đàn Tinh","nhanVatChinh":["Lão già Trương gia"],"blurb":"Hai gia tộc tu chân trên Thánh Đàn Tinh thường nhận nhiều Lôi Đỉnh mỗi lần Lôi Tiên Giới mở.","detail":"Theo ngọc giản của Thân Công Hổ, hai gia tộc này thường giành được nhiều Lôi Đỉnh và không có ai vượt quá Vấn Đỉnh viên mãn theo thông tin ban đầu, nên bị Vương Lâm chọn làm mục tiêu.","nguon":["@c0690"]},{"id":"gia-toc-cua-lao-gia-am-hu","name":"Gia tộc của lão già Âm Hư","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu chân","diaBan":"La Thiên Tinh Vực","nhanVatChinh":["Lão già Trương gia"],"blurb":"Gia tộc nắm giữ Đệ Tam Nhãn như truyền thừa bí mật.","detail":"Đệ Tam Nhãn được xem là thần thông truyền thừa của gia tộc, không dễ truyền ra ngoài; lão già là người đầu tiên trong gia tộc luyện thành thuật này.","nguon":["@c0691"]},{"id":"gia-toc-cua-than-cong-ho","name":"Gia tộc của Thân Công Hổ","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu chân","diaBan":"La Thiên Tinh Vực","nhanVatChinh":["Thân Công Hổ"],"blurb":"Gia tộc gây áp lực lên Thân Công Hổ vì quyết định phụ thuộc Vương Lâm.","detail":"Trong hai mươi năm, gia tộc không chấp nhận lựa chọn của Thân Công Hổ. Ngay cả đại trưởng lão dừng ở Tịnh Niết Kỳ cũng được hắn nghĩ tới như người không đủ tư cách dạy hắn về con đường sống.","nguon":["@c0693"]},{"id":"doc-tu-la-thien-tinh-vuc","name":"Độc tu La Thiên Tinh Vực","cn":"","type":"nhom","typeLabel":"Nhóm tu sĩ","diaBan":"La Thiên Tinh Vực","nhanVatChinh":[],"blurb":"Nhóm độc tu hiếm thấy trong La Thiên Tinh Vực, nơi môn phái và gia tộc chiếm ưu thế.","detail":"Những độc tu có thể tồn tại và đạt tu vi cao tại La Thiên Tinh Vực đều được xem là cực kỳ hùng mạnh, nên họ đặc biệt gây chú ý trước cửa Lôi Tiên Giới.","nguon":["@c0693"]},{"id":"dieu-gia","name":"Diêu gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Tinh cầu đỏ sậm trong La Thiên Tinh Vực","nhanVatChinh":["Diêu Không","Diêu Lạc Đông","Diêu Tích Huyết","Tổ phụ Diêu gia"],"blurb":"Diêu gia là gia tộc ở La Thiên Tinh Vực, có từ đường và tinh cầu đỏ sậm riêng.","detail":"Diêu gia từng loại Diêu Lạc Đông khỏi danh sách vì chuyện rời tộc. Khi Diêu Không trở về cầu cứu, tổ phụ Diêu gia vẫn công nhận Diêu Tích Huyết là tằng tôn nữ mang huyết mạch gia tộc và giao lệnh bài để Diêu Không tới Lôi Tiên Điện.","nguon":["@c0699","@c0795"]},{"id":"gia-toc-cua-nu-tu-van-dinh-dai-vien-man","name":"Gia tộc của nữ tu Vấn Đỉnh đại viên mãn","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu sĩ","diaBan":"không rõ","nhanVatChinh":["Nữ tu mắt phượng","Lý Nguyên","Tổ phụ Diêu gia"],"blurb":"Gia tộc nắm mệnh hồn của Lý Nguyên, khiến hắn phải cung kính với nữ tu. Tổ phụ của nữ tu từng ban đan dược cứu Lý Nguyên khỏi thương thế trăm năm trước.","detail":"Gia tộc này chưa lộ đầy đủ tên gọi và địa bàn, nhưng quyền khống chế mệnh hồn cho thấy họ có ràng buộc rất mạnh với Lý Nguyên. Trong Lôi Tiên Giới, nữ tu dựa vào ràng buộc ấy để buộc Lý Nguyên phối hợp đặt bẫy và ra tay.","nguon":["@c0700"]},{"id":"cat-gia","name":"Cát gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Không rõ trong Lôi Tiên Giới","nhanVatChinh":["Cát Hồng","Lý Nguyên"],"blurb":"Cát gia là gia tộc của Cát Hồng, thế lực giữ mệnh hồn của Lý Nguyên và nuôi dưỡng Thiên Quỷ nhiều năm.","detail":"Trong chương này Cát gia được nhắc như thế lực từng cứu Lý Nguyên nhưng giữ mệnh hồn hắn, đồng thời truyền lại cho Cát Hồng thanh thiết kiếm chuyên đối phó lôi đình và nuôi Tiên Linh nhiều năm.","nguon":["@c0701"]},{"id":"loi-tien-gioi","name":"Lôi tiên giới","cn":"","type":"gioi-vuc","typeLabel":"Giới vực","diaBan":"Lôi tiên giới","nhanVatChinh":["Lão già chủ Lôi tiên giới cầm Lôi quang thiết liên","Vương Lâm","Lý Nguyên","Cát Hồng"],"blurb":"Lôi tiên giới trong chương này hiện lên như nơi do lão già thần bí có quyền can thiệp sâu rộng. Lão tuyên bố lôi thú của bất cứ ai tiến vào nơi này trong một khoảng thời gian đều thuộc về lão.","detail":"Lão già cầm Lôi quang thiết liên nói rõ bất cứ người nào tiến vào Lôi tiên giới thì toàn bộ lôi thú của họ trong tương lai có một khoảng thời gian đều thuộc về lão. Điều này cho thấy lão có địa vị hoặc quyền lực đặc biệt gắn với Lôi tiên giới và đang cần Lôi thú để thực hiện đại sự.","nguon":["@c0703"]},{"id":"de-tu-dich-he-truyen-thua-mai-hoa-thuat","name":"Đệ tử đích hệ truyền thừa Mai hoa thuật","cn":"","type":"truyen-thua","typeLabel":"Nhóm truyền thừa","diaBan":"không rõ","nhanVatChinh":["Lý Nguyên"],"blurb":"Nhóm truyền thừa gắn với Mai hoa thuật, có quy củ nghiêm ngặt về việc học cấm chế. Theo hiểu biết của Vương Lâm, người ngoài không thể học, còn đệ tử đích hệ tùy thân phận cũng chỉ học được một phần.","detail":"Mai hoa thuật không truyền tùy tiện ra ngoài. Trong hệ truyền thừa này, đệ tử đích hệ cũng bị giới hạn, nhiều nhất chỉ học được chín loại cấm chế, còn người có thể học đầy đủ là chưởng môn; quy củ ấy khiến phản ứng của Lý Nguyên trước lời thăm dò của Vương Lâm càng đáng chú ý.","nguon":["@c0705"]},{"id":"ly-gia","name":"Lý gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu chân","diaBan":"La Thiên tinh vực","nhanVatChinh":["Lý Nguyên"],"blurb":"Lý gia từng là một trong sáu gia tộc cổ ở La Thiên tinh vực, nổi danh nhờ phá cấm chế.","detail":"Sau lần tổ tiên vào Lôi tiên giới đầu tiên, Lý gia bị nô ấn khiến hậu nhân mất tiềm lực, không vượt qua Vấn Đỉnh đại viên mãn và tuổi thọ giảm mạnh. Gia tộc suy tàn qua nhiều đời, đến thời Lý Nguyên chỉ còn ba người tính cả hắn.","nguon":["@c0707","@c0798","@c0804"]},{"id":"sau-gia-toc-co-o-la-thien-tinh-vuc","name":"Sáu gia tộc cổ ở La Thiên tinh vực","cn":"","type":"nhom-the-luc","typeLabel":"Nhóm thế lực","diaBan":"La Thiên tinh vực","nhanVatChinh":["Lý Nguyên"],"blurb":"Nhóm sáu gia tộc cổ từng có địa vị lớn ở La Thiên tinh vực, trong đó có Lý gia trước khi suy sụp.","detail":"Lý gia vốn thuộc sáu gia tộc cổ này và nổi danh về cấm chế, nhưng địa vị bị hủy hoại sau khi nô ấn truyền qua hậu nhân khiến gia tộc suy kiệt.","nguon":["@c0707"]},{"id":"la-thien-tinh","name":"La Thiên tinh","cn":"","type":"khac","typeLabel":"Khu vực/thế lực rộng","diaBan":"La Thiên","nhanVatChinh":[],"blurb":"La Thiên tinh được nhắc tới trong lời Lý Nguyên khi nói về sức hút của Phá Diệt cấm. Nhiều người ở khu vực này từng tìm kiếm truyền thừa cấm chế của Lý gia vì uy lực của nó.","detail":"Trong chương này, La Thiên tinh là bối cảnh thế lực rộng liên quan tới danh tiếng của Phá Diệt cấm. Lý Nguyên cho biết vì Lý gia từng bị nô ấn khống chế, truyền thừa bị lan ra ngoài, khiến không ít người ở La Thiên tinh biết tới hoặc truy cầu cấm chế này.","nguon":["@c0710"]},{"id":"huyet-tinh-duoi-huyet-to","name":"Huyết Tinh dưới Huyết Tổ","cn":"","type":"the-luc","typeLabel":"Thế lực tinh cầu","diaBan":"Huyết Tinh","nhanVatChinh":["Diêu Không","Tử Tâm","Huyết nô và Huyết vệ trên Huyết Tinh"],"blurb":"Thế lực do Huyết Tổ dựng trên Huyết Tinh, vận hành bằng hệ thống Huyết nô và Huyết vệ bị lạc ấn khống chế.","detail":"Khi Huyết Tổ gặp biến cố, nô bộc chết hàng loạt, thuộc hạ bước hai bỏ đi; sau đòn tấn công của bản tôn Vương Lâm, Huyết Tinh bị phá và hệ thống khống chế tan rã.","nguon":["@c0720"]},{"id":"tu-chan-gioi","name":"Tu Chân Giới","cn":"","type":"khai-niem","typeLabel":"Thế giới tu sĩ","diaBan":"","nhanVatChinh":[],"blurb":"Không gian tu luyện hiện thời được đặt trong tương quan với thời đại Cổ Thần xa xưa.","detail":"Chương nhấn mạnh thời đại Cổ Thần cách Tu Chân Giới quá xa, và việc thiên lôi luyện vật thành pháp bảo như mảnh lục địa Lôi Tiên Giới là cực kỳ hiếm gặp trong Tu Chân Giới.","nguon":["@c0721"]},{"id":"luyen-khi-si","name":"Luyện Khí Sĩ","cn":"","type":"he-thong-tu-si","typeLabel":"Hệ thống tu sĩ thượng cổ","diaBan":"Thượng cổ","nhanVatChinh":[],"blurb":"Luyện Khí Sĩ là lớp tu sĩ thượng cổ tu luyện nguyên khí.","detail":"Chương dùng Luyện Khí Sĩ để giải thích con đường sau Âm Hư và Dương Thực: tu sĩ hiện tại qua Hóa Nguyên mới miễn cưỡng bước theo dấu vết tu luyện nguyên khí của họ.","nguon":["@c0722"]},{"id":"bon-dai-gia-toc-tu-chan-truyen-thua-tu-tien-gioi","name":"Bốn đại gia tộc tu chân truyền thừa từ Tiên giới","aliases":["Tứ đại gia tộc tu chân","Tứ đại gia tộc","Bốn đại gia tộc tu chân truyền thừa từ Tiên giới"],"cn":"","type":"gia-toc","typeLabel":"Liên minh gia tộc","diaBan":"La Thiên Tinh Vực","nhanVatChinh":["Huyết Thần Tử","Sửu thúc","Thiếu chủ Diêu gia","Lý Nguyên"],"blurb":"Bốn gia tộc tu chân truyền thừa từ Tiên giới tại La Thiên Tinh Vực, nắm giữ cơ duyên Tàng Quyết Các trong Lôi chi Tiên giới.","detail":"Bốn đại gia tộc từng liên thủ phong ấn mảnh vỡ đại lục có Tàng Quyết Các, thường đưa tộc nhân vào Lôi chi Tiên giới thử cơ duyên thu hoạch Tiên thuật và không muốn người ngoài bước vào nơi này.","nguon":["@c0727"]},{"id":"trieu-gia-cua-la-thien-tay-vuc","name":"Triệu gia của La Thiên Tây Vực","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu chân","diaBan":"La Thiên Tây Vực","nhanVatChinh":["Hai tu sĩ Triệu gia của La Thiên Tây Vực"],"blurb":"Gia tộc tu chân ở La Thiên Tây Vực, được hai tu sĩ Vấn Đỉnh trung kỳ tự xưng khi tới gần Dẫn Cơ phủ. Hai người thuộc thế lực này tỏ ra cung kính và không dám vượt ranh giới Vương Lâm đặt ra.","detail":"Khi cột sáng tiết linh từ tiên trận Dẫn Cơ phủ phóng lên trời, hai tu sĩ Vấn Đỉnh trung kỳ bay tới trước và tự xưng là người Triệu gia của La Thiên Tây Vực. Trước lời cảnh cáo của Vương Lâm, họ dừng ngoài phạm vi nghìn trượng và cam kết không vi phạm lời tiền bối.","nguon":["@c0728"]},{"id":"loi-chi-tien-gioi-the-luc","name":"Lôi chi Tiên giới","cn":"","type":"tien-gioi","typeLabel":"Không gian Tiên giới","diaBan":"Tiên giới","nhanVatChinh":[],"blurb":"Không gian Tiên giới từng có vô số Tiên nhân và các phủ giao dịch quy mô lớn trước khi sụp đổ. Dẫn Cơ phủ là một địa điểm giao dịch thuộc Lôi chi Tiên giới khi xưa.","detail":"Theo Lý Nguyên, khi Lôi chi Tiên giới chưa sụp đổ, nơi này có rất nhiều phủ giao dịch để Tiên nhân trao đổi vật cần dùng. Dẫn Cơ phủ là một trong các phủ ấy, nay chỉ còn phế tích sau nhiều lần bị tu sĩ tiến vào tìm kiếm.","nguon":["@c0728"]},{"id":"duong-gia","name":"Đường gia","cn":"","aliases":["La Thiên Nam Vực Đường gia"],"type":"gia-toc","typeLabel":"Gia tộc tu chân","diaBan":"La Thiên Nam Vực","nhanVatChinh":["Đường Ngôn Vân"],"blurb":"Gia tộc của Đường Ngôn Vân tại La Thiên Nam Vực, có nhiều người tiến vào Lôi chi Tiên giới.","detail":"Đường Ngôn Vân là người đi trước dò đường cho Đường gia trong Lôi chi Tiên giới; phía sau còn thân huynh và người trong gia tộc đang tới. Khi hắn nêu tên Đường gia, tu sĩ ngoài phạm vi nghìn trượng biến sắc và liên hệ đến Đường gia ở La Thiên Nam Vực, tuy gia tộc này không phải đại gia tộc truyền thừa từ Tiên giới nhưng quy mô không nhỏ.","nguon":["@c0729"]},{"id":"tang-pham-cac-co-cau","name":"Tàng Phẩm Các","cn":"","type":"truyen-thua","typeLabel":"Cơ cấu truyền thừa tiên thuật","diaBan":"Tàng Phẩm Các trong Lôi Tiên Giới","nhanVatChinh":["Vương Lâm","Lão già họ Trần","Tu sĩ họ Lữ","Tu sĩ họ Tống"],"blurb":"Cơ cấu cất giữ tiên thuật trong Lôi Tiên Giới, cần ít nhất hai gia tộc đồng thời thi triển mới mở được. Người vào sẽ được kiểm tra tư cách để tới các tầng khác nhau.","detail":"Tàng Phẩm Các vận hành như nơi truyền thừa tiên thuật, bên ngoài do các gia tộc giữ, bên trong có không gian sương mù kiểm tra phẩm cấp người vào. Cấp Bát Phẩm Thượng Tiên chỉ vào tầng bốn chọn tiên thuật theo cơ duyên, còn Cửu phẩm tiên quân có thể lên tầng chín tra cứu tiên thuật.","nguon":["@c0735"]},{"id":"tran-gia","name":"Trần gia","cn":"","type":"gia-toc","typeLabel":"Tu chân gia tộc La Thiên","diaBan":"La Thiên Tinh Vực","nhanVatChinh":["Lão già họ Trần"],"blurb":"Gia tộc của lão già họ Trần, có liên quan việc giữ Tàng Phẩm Các. Lão Trần từng đại diện gia tộc mời Hứa Mộc làm trưởng lão khác họ.","detail":"Sau khi Hứa Mộc thể hiện thực lực trước Tàng Phẩm Các, lão già họ Trần hỏi quan hệ của hắn với Hứa gia Đông Lâm Tinh và nếu không thuộc Hứa gia thì mời hắn trở thành trưởng lão khác họ của Trần gia, đồng thời dùng lợi ích để hóa giải tổn thất.","nguon":["@c0735"]},{"id":"sau-gia-toc-truyen-thua-thuong-co-tu-chan-gioi","name":"Sáu gia tộc truyền thừa thượng cổ tu chân giới","cn":"","type":"lien-minh-gia-toc","typeLabel":"Nhóm gia tộc thượng cổ","diaBan":"La Thiên Tinh Vực","nhanVatChinh":["Lý Nguyên"],"blurb":"Nhóm gia tộc xuất hiện từ thời thượng cổ trong La Thiên Tinh Vực. Từng có sáu nhà, nhưng đến hiện tại phần lớn đã suy tàn, chỉ còn hai nhà.","detail":"Trong hệ thống gia tộc La Thiên, ngoài các gia tộc chủ tinh và bốn gia tộc truyền thừa từ tiên giới còn có sáu gia tộc truyền thừa thượng cổ tu chân giới. Nhiều nhà đã suy yếu theo thời gian, Lý gia được nêu như ví dụ về một gia tộc thượng cổ suy tàn.","nguon":["@c0735"]},{"id":"gia-toc-tu-chan-vien-co-la-thien","name":"Gia tộc tu chân viễn cổ La Thiên","cn":"","type":"gia-toc","typeLabel":"Gia tộc viễn cổ thần bí","diaBan":"La Thiên Tinh Vực","nhanVatChinh":[],"blurb":"Gia tộc tu chân còn cổ xưa hơn các thế lực thượng cổ trong La Thiên Tinh Vực. Gia tộc này được mô tả cực kỳ thần bí, có cao thủ chân chính và có thể biết bí ẩn Viễn Cổ Tiên Vực.","detail":"Trong thuyết minh về cấp bậc gia tộc La Thiên, gia tộc tu chân viễn cổ được đặt ở tầng sâu nhất, trải qua biến thiên lịch sử lâu dài trước cả thời Lôi Tiên Điện. Sự tồn tại của họ gắn với những bí ẩn rất cổ xưa, thậm chí có thể liên quan Viễn Cổ Tiên Vực.","nguon":["@c0735"]},{"id":"gia-toc-tu-chan-vo-danh","name":"Gia tộc tu chân vô danh","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu chân","diaBan":"Lôi Tiên Giới","nhanVatChinh":[],"blurb":"Gia tộc tu chân vô danh là một đội tu sĩ chạy trốn trong hư vô Lôi Tiên Giới. Đội này có bảy tám tu sĩ quanh Vấn Đỉnh trung hậu kỳ và bị cánh tay cụt xé xác, hút nguyên thần toàn diệt.","detail":"Trong lúc Vương Lâm truy kích, cánh tay cụt chuyển hướng lao vào một đội bảy tám tu sĩ gia tộc tu chân đang bỏ chạy. Những người này bị xé thân thể, bóp nát nguyên thần và bị hấp thu nguyên lực để cánh tay cụt hồi phục thương thế.","nguon":["@c0739"]},{"id":"hoa-tinh-vuc-the-luc","name":"Hỏa Tinh Vực","cn":"","type":"khu-vuc-tu-si","typeLabel":"Khu vực tu sĩ","diaBan":"Hỏa Tinh Vực","nhanVatChinh":[],"blurb":"Khu vực tu sĩ được dùng làm đối chiếu với uy thế của Phần Tiên Hỏa.","detail":"Khi lão giả mượn thân Vương Lâm thi triển Phần Tiên Hỏa, mức khiếp sợ của các tu sĩ được so sánh với tu sĩ Hỏa Tinh Vực, cho thấy hỏa thuật này vượt xa cảm nhận thông thường của họ về hỏa hệ.","nguon":["@c0742"]},{"id":"vien-co-tien-vuc-the-luc","name":"Viễn cổ tiên vực","cn":"","type":"tien-vuc","typeLabel":"Tiên vực","diaBan":"Viễn cổ tiên vực","nhanVatChinh":[],"blurb":"Viễn cổ tiên vực là tiên vực cổ đã biến mất, được nhắc tới qua vị trí đặc biệt của Triều Tiên Đài trong Lôi tiên giới.","detail":"Theo nhận định của thanh niên đầy tà khí, Triều Tiên Đài từng là nơi gần viễn cổ tiên vực nhất. Khi viễn cổ tiên vực còn tồn tại, tiên nhân viễn cổ hạ giới đặt bước đầu tiên tại nơi này.","nguon":["@c0744"]},{"id":"tu-si-loi-tien-gioi","name":"Tu sĩ Lôi Tiên Giới","cn":"","type":"nhom-tu-si","typeLabel":"Nhóm tu sĩ","diaBan":"Lôi Tiên Giới","nhanVatChinh":[],"blurb":"Nhóm tu sĩ đang ở trong Lôi Tiên Giới khi đại trận của Viêm Lôi Tử kích hoạt. Họ rơi vào hoảng loạn khi toàn giới nứt vỡ và sụp đổ trên phạm vi lớn.","detail":"Khi bốn mươi chín mảnh vỡ đại lục bị kích hoạt, lốc xoáy và lực hút khiến Lôi Tiên Giới sụp đổ lần thứ hai trên phạm vi lớn. Các tu sĩ trong giới này chứng kiến không gian nứt rách, khí tức hủy diệt tràn ra và rơi vào trạng thái kinh hoàng.","nguon":["@c0745"]},{"id":"vu-tien-gioi-the-luc","name":"Vũ Tiên Giới","cn":"","type":"dia-vuc","typeLabel":"Địa vực tiên giới","diaBan":"Tiên giới","nhanVatChinh":["Sát Lục Tiên Quân"],"blurb":"Địa vực tiên giới gắn với danh xưng của Sát Lục Tiên Quân lục phẩm. Thanh niên tà khí nhận ra xuất thân này khi Sát Lục Tiên Quân bước ra từ cổ kính.","detail":"Trong chương, Vũ Tiên Giới được nêu qua danh hiệu “Vũ Tiên Giới, lục phẩm Sát Lục Tiên Quân”. Đây là nguồn gốc hoặc hệ thuộc của nguyên thần đệ nhất thần được Viêm Lôi Tử đưa vào Tiên Giới Đại Trận.","nguon":["@c0746"]},{"id":"thanh-thuy-quoc","name":"Thanh Thủy Quốc","cn":"","type":"quoc-gia","typeLabel":"Quốc gia thượng cổ","diaBan":"Thượng cổ tu chân giới","nhanVatChinh":["Thanh Thủy"],"blurb":"Quốc gia thượng cổ tu chân giới nơi Thanh Thủy từng là thái tử. Lai lịch này được Viêm Lôi Tử kể lại khi nói về Thanh Thủy Tiên Quân.","detail":"Theo Viêm Lôi Tử, Thanh Thủy là thái tử của Thanh Thủy Quốc trong thượng cổ tu chân giới, sau đó phi thăng đến Lôi Tiên Giới và trở thành Tiên Quân. Thanh Thủy Quốc vì vậy là gốc thân phận phàm-trần/tu chân giới của Thanh Thủy trước khi bước vào tiên giới.","nguon":["@c0746"]},{"id":"phong-tien-gioi","name":"Phong Tiên Giới","cn":"","type":"tien-gioi","typeLabel":"Tiên giới","diaBan":"không rõ","nhanVatChinh":[],"blurb":"Một trong hai đại tiên giới được Viêm Lôi Tử nhắc tới khi đề nghị cùng Thanh Thủy truy tìm nguyên do biến cố.","detail":"Viêm Lôi Tử nói có thể toàn lực tương trợ Thanh Thủy đi tìm nguyên nhân tại Phong Tiên Giới cùng Điện Tiên Giới, trong mạch nghi vấn về việc các Tiên Quân từng mất thần trí.","nguon":["@c0747"]},{"id":"dien-tien-gioi","name":"Điện Tiên Giới","cn":"","type":"tien-gioi","typeLabel":"Tiên giới","diaBan":"không rõ","nhanVatChinh":[],"blurb":"Một đại tiên giới được Viêm Lôi Tử nhắc cùng Phong Tiên Giới trong đề nghị truy tìm nguyên nhân biến cố.","detail":"Điện Tiên Giới được nêu như nơi Thanh Thủy có thể cùng Viêm Lôi Tử đi tìm manh mối về nguyên nhân Tiên Quân mất thần trí và sự sụp đổ của Lôi Tiên Giới.","nguon":["@c0747"]},{"id":"ba-tien-gioi-con-lai","name":"Ba tiên giới còn lại","cn":"","type":"nhom-the-luc","typeLabel":"Nhóm tiên giới","diaBan":"không rõ","nhanVatChinh":[],"blurb":"Nhóm tiên giới được Viêm Lôi Tử nhắc khi nói các Tiên Quân khác cũng từng mất thần trí như Thanh Thủy.","detail":"Theo lời Viêm Lôi Tử, khi Thanh Thủy mất thần trí, Tiên Quân trong ba tiên giới còn lại cũng rơi vào tình trạng tương tự, cho thấy biến cố có phạm vi rộng hơn một cá nhân.","nguon":["@c0747"]},{"id":"tu-dai-tien-gioi","name":"Tứ đại tiên giới","type":"khac","typeLabel":"Cấu trúc tiên giới","diaBan":"Viễn cổ tiên vực","nhanVatChinh":[],"blurb":"Bốn đại tiên giới gặp hạo kiếp và sụp đổ toàn bộ sau khi Thanh Thủy bị phong ấn.","detail":"Viêm Lôi Tử nêu sau khi Thanh Thủy bị phong ấn, tứ đại tiên giới gặp hạo kiếp và sụp đổ toàn bộ; quyển trục Tu Chân Liên Minh được đồn ghi nguyên nhân thật sự của biến cố này.","nguon":["@c0748"]},{"id":"loi-tien-dien","name":"Lôi Tiên điện","cn":"","type":"the-luc","typeLabel":"Thế lực","diaBan":"Lôi Tiên Giới","nhanVatChinh":["Sáu sứ giả Lôi Tiên điện","Thân Công Hổ","Vương Lâm"],"blurb":"Thế lực kiểm soát truyền tống trận nơi các tu sĩ phá vây trong chương này. Sáu sứ giả của thế lực này bị Vương Lâm và đám tu sĩ đánh tan, trong khi Thân Công Hổ tránh ra tay vì từng chịu ân của Lôi Tiên điện.","detail":"Lôi Tiên điện có sứ giả canh giữ truyền tống trận, ngăn hơn trăm tu sĩ rời khỏi nơi nguy hiểm. Trong cuộc phá vây, nhiều sứ giả bị giết hoặc bị Trảm La quyết chém tan trong cột sáng; Vương Lâm cũng muốn tránh khả năng truyền tống thẳng tới Lôi Tiên điện nên chấp nhận việc trận pháp bị phá hủy để đổi điểm đến.","nguon":["@c0753"]},{"id":"dam-tu-si-pha-vay","name":"Đám tu sĩ phá vây","cn":"","type":"nhom-lam-thoi","typeLabel":"Nhóm lâm thời","diaBan":"Truyền tống trận của Lôi Tiên Điện","nhanVatChinh":["Vương Lâm","Tây Tử Phượng","Tu sĩ Dương Thực vô danh","Đám tu sĩ Vấn Đỉnh, Âm Hư, Dương Thực được cứu"],"blurb":"Nhóm hơn trăm tu sĩ Vấn Đỉnh, Âm Hư và Dương Thực tạm thời hợp lực theo Vương Lâm phá vòng vây.","detail":"Trước áp lực bị giam tại truyền tống trận, nhóm tu sĩ đồng loạt theo Vương Lâm hô nhường đường và tiến lên, tạo khí thế khiến sứ giả Lôi Tiên điện phải lùi. Họ hợp lực vây giết sứ giả, lần lượt thoát qua cột sáng và ghi nhớ danh xưng Hứa Mộc như ân nhân.","nguon":["@c0753"]},{"id":"hon-muoi-gia-toc-tu-chan-la-thien","name":"Hơn mười gia tộc tu chân La Thiên","cn":"","aliases":[],"type":"gia-toc","typeLabel":"Liên nhóm gia tộc tu chân","diaBan":"Tinh vực La Thiên, đại lục thứ tư","nhanVatChinh":["Hơn trăm tu sĩ sống sót từ Lôi Tiên Giới","Các gia chủ hơn mười gia tộc tu chân La Thiên"],"blurb":"Nhóm gia tộc có tu sĩ sống sót trở về từ Lôi Tiên Giới. Họ cùng truyền tụng Hứa Mộc và liên hợp để tránh bị Lôi Tiên điện truy cứu chuyện xâm nhập cấm địa truyền tống trận.","detail":"Sau khi hơn trăm tu sĩ được truyền tống về đại lục thứ tư La Thiên, các gia tộc của họ đều biết chuyện tộc nhân từng xông vào truyền tống trận thuộc cấm địa Lôi Tiên điện. Vì nguy cơ liên lụy toàn tộc, các gia chủ lựa chọn liên hợp, xóa bỏ trọng tâm sự việc và đồng thời lan truyền danh tiếng Hứa Mộc để phân tán áp lực.","nguon":["@c0754"]},{"id":"cac-gia-toc-lon-nho-cua-dai-luc-thu-tu-la-thien","name":"Các gia tộc lớn nhỏ của đại lục thứ tư La Thiên","cn":"","aliases":[],"type":"gia-toc","typeLabel":"Nhóm gia tộc tu chân","diaBan":"Đại lục thứ tư La Thiên","nhanVatChinh":["Hơn trăm tu sĩ sống sót từ Lôi Tiên Giới"],"blurb":"Các gia tộc trên đại lục thứ tư La Thiên tiếp nhận những tu sĩ sống sót trở về từ Lôi Tiên Giới. Lực lượng hợp lại của họ khiến Lôi Tiên điện khó công khai truy cứu chuyện truyền tống trận.","detail":"Khi một trăm dao động truyền tống xuất hiện trên đại lục thứ tư La Thiên, các tu sĩ sống sót lần lượt trở về những gia tộc lớn nhỏ khác nhau. Từ các gia tộc này, tin tức về thảm họa Lôi Tiên Giới và tên Hứa Mộc nhanh chóng lan khắp La Thiên, đồng thời hình thành áp lực tập thể đối với Lôi Tiên điện.","nguon":["@c0754"]},{"id":"tien-di-toc","name":"Tiên Di tộc","cn":"","type":"chung-toc","typeLabel":"Chủng tộc","diaBan":"Đại lục lơ lửng giữa không trung","nhanVatChinh":["Nam tử áo vải Tiên Di tộc","Lão nhân Tiên Di tộc tóc bạc"],"blurb":"Chủng tộc sống trên đại lục lơ lửng phía sau bức tường thịt khổng lồ. Người trong tộc có ký hiệu trên mặt, tay chân và mi tâm, tự xưng hạ dân trước Thượng tiên, nhận ra hệ thống Bát phẩm thượng tiên và pháp bảo của Tiêu Dao tiên vương.","detail":"Tiên Di tộc xuất hiện khi Vương Lâm vượt qua khe hở trong bức tường thịt và tới đại lục lơ lửng. Hơn trăm người trong tộc lao tới bằng cầu vồng, đều mặc áo vải thô và mang ký hiệu; lão nhân tóc bạc đại diện cung kính gọi Vương Lâm là Thượng tiên vì nhận ra Tử Mẫu Đạo Khô trên tay hắn. Cách họ nhắc tới tiên dụ cuối cùng của Tiêu Dao tiên vương khiến Vương Lâm nghi ngờ tộc này vẫn giữ nhận thức cổ xưa về Tiên giới.","nguon":["@c0755"]},{"id":"tien-nhan-thuong-tien","name":"Tiên nhân / Thượng tiên","cn":"","type":"nhom-than-phan","typeLabel":"Nhóm thân phận","diaBan":"Tiên giới","nhanVatChinh":["Vương Lâm"],"blurb":"Nhóm thân phận mà lão nhân dùng để nhận Vương Lâm khi gặp hắn tại nơi cư trú của tộc Tiên Di/Tiên Tuyển.","detail":"Lão nhân căn cứ điển tịch của bộ tộc để nhận ra Vương Lâm là thượng tiên, trong khi nhiều tộc nhân vì lâu không gặp người của tiên giới nên sợ hãi người lạ. Tháp Sơn thì công khai phủ nhận niềm tin vào tiên nhân và muốn dùng thực lực của mình thử giết tiên.","nguon":["@c0756"]},{"id":"toc-tien-tuyen","name":"Tộc Tiên Tuyển","cn":"","type":"bo-toc","typeLabel":"Bộ tộc","diaBan":"Thế giới U Minh thú","nhanVatChinh":["Tháp Sơn","Lão nhân Tiên Di tộc tóc bạc"],"blurb":"Bộ tộc sống trong thế giới U Minh thú, tin rằng mình được tiên nhân tuyển chọn. Nhiều đời họ hiến mạng bảo vệ Huyền Âm đỉnh theo mệnh lệnh được cho là của Tiêu Dao tiên vương.","detail":"Tộc Tiên Tuyển được điển tịch trong tộc ghi lại là do Tiêu Dao tiên vương đưa vào thế giới U Minh thú để đời đời bảo vệ Huyền Âm đỉnh cho tới khi ông quay lại. Qua nhiều thế hệ, tộc nhân liên tục chết vì sương mù hóa thú, không ai thấy tiên nhân, khiến Tháp Sơn bắt đầu nghi ngờ niềm tin rằng họ được tuyển chọn và không bị bỏ rơi.","nguon":["@c0759"]},{"id":"loi-chi-tien-gioi","name":"Lôi Chi Tiên Giới","cn":"","type":"tien-gioi","typeLabel":"Tiên giới","diaBan":"Chưa rõ","nhanVatChinh":["Thanh Thủy Tiên Quân"],"blurb":"Một trong các tiên giới được nhắc qua Thanh Thủy Tiên Quân. Vương Lâm dùng Thanh Thủy làm đối chiếu khi cảm nhận khí tức của nam nhân áo xanh.","detail":"Trong lúc phân tích lực lượng của nam nhân áo xanh, Vương Lâm nhận thấy khí tức vừa giống tiên lực vừa chứa nguyên lực, nên liên hệ tới Thanh Thủy Tiên Quân của Lôi Chi Tiên Giới. Chương này chỉ nhắc Lôi Chi Tiên Giới như mốc so sánh về tiên lực.","nguon":["@c0762","@c0802"]},{"id":"dong-tam-tinh-huong-gia","name":"Đông Tâm Tinh Hướng gia","cn":"","type":"gia-toc","typeLabel":"Thượng cổ tu chân gia tộc","diaBan":"Đông Tâm Tinh","nhanVatChinh":["Vương Lâm","Lý Mộ Uyển"],"blurb":"Thượng cổ tu chân gia tộc trên Đông Tâm Tinh, một trong các thế lực ủng hộ Lôi Tiên Điện tiến quân Liên Minh Tinh Vực.","detail":"Hướng gia chủ động tìm Lôi Tiên Điện, cùng một thượng cổ tu chân gia tộc khác thúc đẩy kế hoạch mở thông đạo tới Liên Minh Tinh Vực. Đây cũng là mục tiêu Vương Lâm quyết phải tìm đến vì phương pháp làm Lý Mộ Uyển thức tỉnh.","nguon":["@c0769"]},{"id":"mot-thuong-co-tu-chan-gia-toc-khac","name":"Một thượng cổ tu chân gia tộc khác","cn":"","type":"gia-toc","typeLabel":"Thượng cổ tu chân gia tộc","diaBan":"La Thiên Tinh Vực","nhanVatChinh":[],"blurb":"Thượng cổ gia tộc chưa nêu tên, cùng Hướng gia và Lôi Tiên Điện tạo thành ba thế lực lớn thúc đẩy chiến tranh.","detail":"Gia tộc này được nhắc như một trong hai thượng cổ tu chân gia tộc ủng hộ Lôi Tiên Điện. Dưới ý chí của ba thế lực lớn, các gia tộc tu chân còn lại tại La Thiên không dám không theo kế hoạch tiến quân và Phong Tiên.","nguon":["@c0769"]},{"id":"gia-toc-tu-chan-vien-co-than-bi","name":"Gia tộc tu chân viễn cổ thần bí","cn":"","type":"gia-toc","typeLabel":"Gia tộc viễn cổ","diaBan":"La Thiên Tinh Vực","nhanVatChinh":[],"blurb":"Gia tộc viễn cổ gửi thư triệu tập, nâng đại hội Phong Tiên thành cơ hội hóa tiên nguyên và thành tựu thực tiên.","detail":"Đạo thư triệu tập của gia tộc này khiến sĩ khí chuẩn bị chiến tranh của La Thiên tăng đến đỉnh. Nội dung nêu 108 người được Phong Tiên có thể nhập Thăng Tiên Trì, hóa thể nguyên thành tiên nguyên và thành tựu thực tiên.","nguon":["@c0769"]},{"id":"huyen-tran-tinh-ba-tu-si-am-hu","name":"Huyền Trần Tinh ba tu sĩ Âm Hư","cn":"","type":"nhom-tu-si","typeLabel":"Nhóm tu sĩ địa phương","diaBan":"Huyền Trần Tinh, La Thiên Tây Vực","nhanVatChinh":["Âu Dương Đàn","Trần huynh","Lão nhân thứ hai của Huyền Trần Tinh"],"blurb":"Nhóm ba tu sĩ Âm Hư đại diện hoặc canh giữ Huyền Trần Tinh khi đoàn Vương Lâm đi ngang qua. Họ nhận ra Vương Lâm giống Hứa Mộc trong Thiên Khung Lệnh và quyết định báo tin cho Diêu tộc.","detail":"Ba người gồm Âu Dương Đàn và hai lão nhân từ Huyền Trần Tinh bay ra hỏi lai lịch đoàn người. Sau khi Âu Dương Đàn nhận ra hình ảnh Hứa Mộc trên Thiên Khung Lệnh, cả nhóm bàn chuyện báo tin cho Diêu gia để đổi trọng thưởng và cơ hội liên quan Phong Tiên.","nguon":["@c0770"]},{"id":"tu-dai-gia-toc-ke-thua-tien-gioi","name":"Tứ đại gia tộc kế thừa tiên giới","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"La Thiên Tinh Vực","nhanVatChinh":["Diêu gia"],"blurb":"Bốn gia tộc lớn kế thừa tiên giới tại La Thiên Tinh Vực. Diêu gia được nhắc là đứng đầu trong nhóm này.","detail":"Khi phân tích nguyên nhân bị truy sát, Vương Lâm nhắc Diêu gia là một trong tứ đại gia tộc kế thừa tiên giới và đứng đầu nhóm này. Thế lực của Diêu gia được hắn đánh giá có người giống Huyết Tổ, thậm chí mạnh hơn Huyết Tổ.","nguon":["@c0771"]},{"id":"cac-gia-toc-tu-chan-tinh-phu-can-co-lien-he-voi-dieu-gia","name":"Các gia tộc tu chân tinh phụ cận có liên hệ với Diêu gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu chân","diaBan":"La Thiên Tinh Vực","nhanVatChinh":["Hai mươi tám tu sĩ vây chặn","Trung niên văn sĩ","Hai lão nhân Âm Hư"],"blurb":"Mạng lưới gia tộc tu chân tinh phụ cận có quan hệ với Diêu gia. Vương Lâm suy đoán lực lượng vây chặn mình trong thời gian rất ngắn đến từ nhóm thế lực này.","detail":"Sau khi bị hai mươi tám tu sĩ từ bốn hướng bao vây chỉ sau khoảng hai nén hương, Vương Lâm bác khả năng toàn bộ là tộc nhân Diêu gia. Hắn suy luận những người này có thể đến từ các gia tộc tu chân tinh gần đó, có liên hệ với Diêu gia và hưởng ứng lệnh truy sát Hứa Mộc.","nguon":["@c0771"]},{"id":"gia-toc-linh-minh-tinh","name":"Gia tộc Linh Minh tinh","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu chân","diaBan":"Linh Minh tinh","nhanVatChinh":["Âm Hư tu sĩ cầu xin từ Linh Minh tinh"],"blurb":"Gia tộc Linh Minh tinh được nhắc qua lời cầu xin của một Âm Hư tu sĩ. Sau khi vòng vây tan rã, người này hứa toàn bộ gia tộc sẽ không tham dự chuyện giữa Hứa Mộc và Diêu gia.","detail":"Một Âm Hư tu sĩ bỏ thân thể để nguyên thần chạy trốn rồi xin Vương Lâm tha mạng, tuyên bố gia tộc Linh Minh tinh của hắn từ nay không can dự xung đột Hứa Mộc–Diêu gia. Lời cầu xin cho thấy các gia tộc ngoài Diêu gia bị trọng thưởng lôi kéo vào cuộc truy sát.","nguon":["@c0772"]},{"id":"huyen-tran-tinh-the-luc","name":"Huyền Trần Tinh","cn":"","type":"dia-ban","typeLabel":"Địa bàn liên quan thế lực","diaBan":"Huyền Trần Tinh","nhanVatChinh":["Văn sĩ trung niên của Huyền Trần Tinh","Diêu Trường Không"],"blurb":"Huyền Trần Tinh được nhắc như nơi văn sĩ trung niên từng bóp nát ngọc giản để gọi Diêu Trường Không. Sự liên hệ này nối nhóm chặn đường với tộc nhân Diêu gia xuất hiện trực tiếp.","detail":"Chương này nhắc lại việc văn sĩ trung niên của Huyền Trần Tinh bóp nát ngọc giản, dẫn tới thanh niên Diêu Trường Không xuất hiện trong kiếm quang. Huyền Trần Tinh vì vậy là đầu mối liên quan tới việc điều động người trong mạch truy sát Hứa Mộc.","nguon":["@c0772"]},{"id":"tam-phuong-la-thien-dong-vuc","name":"Tam Phượng La Thiên Đông Vực","cn":"","type":"danh-xung-nhom","typeLabel":"Danh xưng nhóm","diaBan":"La Thiên Đông Vực","nhanVatChinh":["Diêu Băng Vân"],"blurb":"Danh xưng dành cho ba nữ tu nổi bật ở La Thiên Đông Vực; Diêu Băng Vân được tôn xưng là Hàn Phượng, một trong Tam Phượng.","detail":"Trong chương này, Diêu Băng Vân được giới thiệu là Hàn Phượng, một trong Tam Phượng La Thiên Đông Vực. Danh xưng này gắn với uy danh của nàng trong khu vực Đông Vực và xuất hiện khi nàng truy đuổi Vương Lâm sau trận Diêu Trường Không tử chiến.","nguon":["@c0773"]},{"id":"cac-tu-chan-gia-toc-lien-hop","name":"Các tu chân gia tộc liên hợp","cn":"","type":"lien-minh","typeLabel":"Liên minh lâm thời","diaBan":"La Thiên Tinh Vực","nhanVatChinh":[],"blurb":"Các tu chân gia tộc liên hợp từng tạo đội hai mươi tám tu sĩ chặn giết Hứa Mộc. Sau khi đội này bị diệt phần lớn, nhiều gia tộc tiếp tục được Diêu gia liên hệ để tập hợp tại La Thiên Tây Vực.","detail":"Lực lượng liên hợp gồm nhiều gia tộc có liên quan đến cuộc truy sát Hứa Mộc. Đội hai mươi tám người từng bị Hứa Mộc giết mất hai mươi sáu, chỉ còn hai người chạy thoát và tuyên bố không nhúng tay vào ân oán Hứa Mộc với Diêu gia; về sau Diêu gia vẫn liên hệ nhiều tu chân gia tộc khác để hình thành phòng tuyến phong tỏa tại La Thiên Tây Vực.","nguon":["@c0774"]},{"id":"cac-tu-chan-gia-toc-tro-giup-dieu-gia","name":"Các tu chân gia tộc trợ giúp Diêu gia","cn":"","type":"lien-minh","typeLabel":"Liên minh truy sát","diaBan":"La Thiên Tây Vực","nhanVatChinh":["Vương Lâm","Diêu Băng Vân"],"blurb":"Nhiều gia tộc bản địa Tây Vực bị Diêu gia lôi kéo tham gia vây giết Hứa Mộc.","detail":"Các gia tộc này tham gia vì lợi ích và trọng thưởng của Diêu gia, trở thành một phần mạng lưới phong tỏa Vương Lâm. Việc tham chiến khiến họ bị Vương Lâm chọn làm mục tiêu trả thù bằng đồ tinh.","nguon":["@c0775"]},{"id":"cac-tu-chan-gia-toc-truy-sat-hua-moc","name":"Các tu chân gia tộc truy sát Hứa Mộc","cn":"","type":"lien-minh","typeLabel":"Liên minh lâm thời","diaBan":"La Thiên Tinh Vực","nhanVatChinh":["Vương Lâm","Diêu Băng Vân"],"blurb":"Liên minh nhiều gia tộc từ các vực tham gia truy sát Hứa Mộc theo thế phong tỏa của Diêu gia.","detail":"Sau các cuộc trả thù và trận vạn trượng, một số gia tộc sợ hãi rút lui, còn số khác xem Hứa Mộc là đại họa cần tiêu diệt. Liên minh này chịu tổn thất nặng do Cửu Tuyệt Tổn Thần Trận và nguyên thần Huyết Tổ tự bạo.","nguon":["@c0776"]},{"id":"tu-chan-gia-toc-la-thien-tay-vuc","name":"Tu chân gia tộc La Thiên Tây Vực","cn":"","type":"gia-toc","typeLabel":"Thế lực khu vực","diaBan":"La Thiên Tây Vực","nhanVatChinh":["Vương Lâm"],"blurb":"Các gia tộc Tây Vực có căn cơ tại địa bàn bị Vương Lâm trả thù trực tiếp uy hiếp.","detail":"Vì sợ tiểu bối và căn cơ gia tộc bị diệt, nhiều gia tộc Tây Vực cân nhắc lợi hại rồi rút khỏi tuyến phong tỏa truy sát Hứa Mộc.","nguon":["@c0776"]},{"id":"tu-chan-gia-toc-la-thien-bac-vuc","name":"Tu chân gia tộc La Thiên Bắc Vực","cn":"","type":"gia-toc","typeLabel":"Thế lực khu vực","diaBan":"La Thiên Bắc Vực","nhanVatChinh":[],"blurb":"Các gia tộc Bắc Vực có tu sĩ tham gia đội truy sát Hứa Mộc.","detail":"Một tu sĩ Âm Hư xuất thân từ La Thiên Bắc Vực ở gần nguyên thần Huyết Tổ khi tự bạo nên thân thể và nguyên thần đều tan biến.","nguon":["@c0776"]},{"id":"tu-chan-gia-toc-la-thien-nam-vuc","name":"Tu chân gia tộc La Thiên Nam Vực","cn":"","type":"gia-toc","typeLabel":"Thế lực khu vực","diaBan":"La Thiên Nam Vực","nhanVatChinh":[],"blurb":"Các gia tộc Nam Vực có tu sĩ tham gia truy sát Hứa Mộc.","detail":"Một tu sĩ xuất thân từ La Thiên Nam Vực bị sóng gợn từ nguyên thần Huyết Tổ tự bạo cuốn tới, thân thể hóa thành sương máu.","nguon":["@c0776"]},{"id":"cac-tu-chan-gia-toc-la-thien-bac-vuc","name":"Các tu chân gia tộc La Thiên Bắc Vực","cn":"","type":"gia-toc","typeLabel":"Thế lực địa phương","diaBan":"La Thiên Bắc Vực","nhanVatChinh":["Vương Lâm"],"blurb":"Một số gia tộc Bắc Vực tham gia truy sát Hứa Mộc nhưng dao động khi hắn quay về địa bàn của họ.","detail":"Sau khi nhớ tới việc đồ tinh ở Tây Vực, một bộ phận tu sĩ Bắc Vực sợ Hứa Mộc trả thù căn cơ gia tộc nên lựa chọn rút khỏi cuộc truy sát, dù vẫn còn nhiều kẻ tiếp tục đuổi giết.","nguon":["@c0777"]},{"id":"cac-tu-chan-gia-toc-khac","name":"Các tu chân gia tộc khác","cn":"","type":"lien-minh","typeLabel":"Nhóm truy sát","diaBan":"La Thiên Tinh Vực","nhanVatChinh":["Vương Lâm"],"blurb":"Các gia tộc ngoài Diêu gia vẫn tiếp tục tham gia truy sát Vương Lâm.","detail":"Những tu sĩ này cùng Diêu gia bám theo Vương Lâm từ Tây Vực sang Bắc Vực, khiến hắn quyết định dẫn tất cả tới Vọng Nguyệt để mượn hung vật giải quyết.","nguon":["@c0777"]},{"id":"tu-chan-gia-toc-la-thien-tinh-vuc","name":"Tu chân gia tộc La Thiên Tinh Vực","cn":"","type":"gia-toc","typeLabel":"Tu chân gia tộc","diaBan":"La Thiên Tinh Vực","nhanVatChinh":[],"blurb":"Các tu chân gia tộc trong La Thiên Tinh Vực tham gia hoặc chịu ảnh hưởng bởi cuộc truy sát Hứa Mộc và kế hoạch huyết tẩy.","detail":"Trong cuộc truy sát Hứa Mộc, nhiều tu chân gia tộc La Thiên tới trợ chiến; khi Vọng Nguyệt thức tỉnh và tàn sát, người của các gia tộc này chết hơn phân nửa, cho thấy họ bị cuốn vào kế hoạch huyết tẩy trước đại chiến tinh vực.","nguon":["@c0781"]},{"id":"lien-minh-tinh-vuc","name":"Liên minh Tinh vực","cn":"","type":"the-luc","typeLabel":"Thế lực","diaBan":"Liên minh Tinh vực","nhanVatChinh":["Vương Lâm"],"blurb":"Liên minh Tinh vực là nơi Vương Lâm dự định trở về để tiếp tục khống chế đại đỉnh.","detail":"Sau khi đoạt lại đại đỉnh nhưng chỉ có liên hệ mơ hồ qua phù văn của Tham Lang, Vương Lâm cho rằng khi trở về Liên minh Tinh vực, hắn sẽ có điều kiện khống chế hoàn toàn uy lực của đại đỉnh.","nguon":["@c0785"]},{"id":"tien-tuyen-toc","name":"Tiên Tuyển tộc","cn":"","type":"toc","typeLabel":"Tộc quần","diaBan":"Thanh Linh tinh","nhanVatChinh":["Lão già Tiên Tổ","Người Tiên Tuyển tộc","Vương Lâm"],"blurb":"Tộc quần đã tới Thanh Linh tinh thuận lợi và nhận Vương Lâm là ân công.","detail":"Lão già Tiên Tổ dẫn hơn mười người Tiên Tuyển tộc đến nghênh đón Vương Lâm. Họ được Vương Lâm cho an cư trên Thanh Linh tinh và giao nhiệm vụ phòng hộ nơi này trong thời gian hắn bế quan.","nguon":["@c0790"]},{"id":"gia-toc-tu-chan-truyen-thua-thuong-co","name":"Gia tộc tu chân truyền thừa thượng cổ","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu chân","diaBan":"La Thiên Tinh vực","nhanVatChinh":[],"blurb":"Các gia tộc tu chân truyền thừa thượng cổ ở La Thiên bị uy thế Lôi Tiên điện vượt qua sau sự kiện bắt giữ mãnh thú khổng lồ.","detail":"Sau khi tin Lôi Tiên điện bắt giữ mãnh thú khổng lồ ở La Thiên Bắc vực lan ra, danh vọng của Lôi Tiên điện dâng cao, vượt lên trên nhiều gia tộc tu chân truyền thừa thượng cổ. Dòng chính các gia tộc này cũng bị cuốn vào cuộc tranh đoạt phong một trăm linh tám tiên trước chiến tranh với Liên minh Tinh vực.","nguon":["@c0791"]},{"id":"dang-toc","name":"Đằng tộc","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Không rõ","nhanVatChinh":["Đằng Hóa Nguyên","Đằng Liệt"],"blurb":"Đằng tộc được nhắc lại trong chuỗi nhân quả thù cũ của Vương Lâm.","detail":"Khi suy xét Ý cảnh Nhân quả, Vương Lâm nhắc tới việc hắn giết Đằng Liệt, Đằng Hóa Nguyên giết cha mẹ hắn, rồi hắn diệt Đằng tộc. Đằng tộc vì vậy trở thành một mắt xích quan trọng trong nhận thức của hắn về nhân và quả.","nguon":["@c0791"]},{"id":"yeu-linh","name":"Yêu Linh","cn":"","type":"loai-ton-tai","typeLabel":"Loại tồn tại / thế lực yêu dị","diaBan":"không rõ","nhanVatChinh":["Huyết Thần Tử"],"blurb":"Tồn tại yêu dị được Diêu Vân cho là đã nhập vào lão tổ Diêu Gia. Nhận định này giải thích vì sao Diêu Gia biến chất và hy sinh tộc nhân để duy trì pháp bảo.","detail":"Khi biết số phận của Diêu Băng Vân và Mộng Vân, Diêu Vân cho rằng đại ca năm xưa rời bỏ Diêu Gia là đúng, bởi lão tổ đã bị Yêu Linh nhập thể. Từ đó Diêu Gia dưới tay lão tổ không còn là Diêu Gia ngày xưa trong mắt hắn.","nguon":["@c0796"]},{"id":"mach-truyen-thua-tien-de-bach-pham","name":"Mạch truyền thừa Tiên đế Bạch Phàm","cn":"","type":"truyen-thua","typeLabel":"Truyền thừa sư môn","diaBan":"không rõ","nhanVatChinh":["Bạch Phàm","Thanh Thủy","Vương Lâm"],"blurb":"Mạch truyền thừa được xác lập qua thần thông Hô Phong của Tiên đế Bạch Phàm.","detail":"Thanh Thủy gọi Bạch Phàm là sư tôn và nhận Vương Lâm là sư đệ vì Vương Lâm học được Hô Phong, qua đó khẳng định Vương Lâm là đại truyền nhân của sư tôn hắn và không đến lượt Diêu gia xử trí.","nguon":["@c0801"]},{"id":"thien-cang","name":"Thiên Cang","cn":"","type":"khac","typeLabel":"Thiết chế tiên vị","diaBan":"Lôi Tiên Điện","nhanVatChinh":[],"blurb":"Thiên Cang là nhóm ba mươi sáu tiên được Thanh Thủy nhắc trong cơ chế thăng tiến của Lôi Tiên Điện. Những người thuộc nhóm này có cơ hội vào tiên trì.","detail":"Khi chỉ đường cho Vương Lâm, Thanh Thủy nói một trăm lẻ tám Tiên của Lôi Tiên Điện cùng ba mươi sáu tiên Thiên Cang đều có cơ hội thăng tiến vào tiên trì. Đây là bậc vị trí liên quan trực tiếp đến cơ duyên ngưng tụ tiên nguyên.","nguon":["@c0804"]},{"id":"gia-toc-vien-co-than-bi","name":"Gia tộc viễn cổ thần bí","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"La Thiên Tinh Vực","nhanVatChinh":[],"blurb":"Một thế lực gia tộc viễn cổ được nhắc trong bối cảnh lần phong tiên một trăm lẻ tám tiên.","detail":"Chương chỉ nêu thế lực này cùng các lợi ích và lời hứa liên quan đến cuộc tranh đoạt tiên vị do Lôi Tiên Điện triển khai, chưa công bố danh tính cụ thể.","nguon":["@c0805"]},{"id":"nam-ky-tam-kiet","name":"Tam kiệt Nam Vực","cn":"","aliases":["Nam Kỹ Tam Kiệt"],"type":"danh-xung","typeLabel":"Danh xưng nhóm","diaBan":"Nam vực La Thiên","nhanVatChinh":["Chiến Không Liệt","Thân Công Hổ","Đường Ngôn Phong"],"blurb":"Danh xưng dành cho ba nhân vật nổi danh Nam vực La Thiên: Chiến Không Liệt, Thân Công Hổ và Đường Ngôn Phong.","detail":"Chiến Không Liệt, Thân Công Hổ và Đường Ngôn Phong đại danh đỉnh đỉnh ở Nam vực La Thiên, được người đời xưng gọi là Nam Kỹ Tam Kiệt; cả ba đều có mặt trên phiến đá đỏ thẫm dự cuộc tranh đoạt phong hào tại Địa Viêm Tinh.","nguon":["@c0806"]},{"id":"nam-vuc-la-thien","name":"Nam Vực La Thiên","cn":"","type":"khu-vuc","typeLabel":"Khu vực tu chân","diaBan":"Nam Vực trong La Thiên Tinh Vực","nhanVatChinh":["Vương Lâm","Đường Ngôn Phong","Chiến Vân","Chiến Không Liệt"],"blurb":"Nam Vực La Thiên là khu vực diễn ra cuộc tranh đoạt một trăm lẻ tám tư cách phong tiên. Vương Lâm tuyên bố muốn đứng thứ nhất trong danh sách này.","detail":"Cuộc tranh đoạt tại Nam Vực La Thiên có một trăm lẻ tám tư cách, trong đó Vương Lâm không nhắm bảy mươi hai Địa sát mà muốn đoạt vị trí thuộc ba mươi sáu Thiên Cang. Tuyên bố của hắn khiến toàn trường chấn động và kéo theo việc nhiều gia tộc La Thiên đứng ra tiến cử.","nguon":["@c0807"]},{"id":"trinh-gia","name":"Trịnh gia","cn":"","type":"gia-toc","typeLabel":"Tu chân gia tộc","diaBan":"La Thiên Tinh Vực","nhanVatChinh":["Người phát ngôn Trịnh gia"],"blurb":"Trịnh gia là gia tộc La Thiên đứng ra tiến cử Hứa Mộc tham chiến. Đại diện của họ lên tiếng sau các gia tộc Trần, Triệu và Lý.","detail":"Khi lão già họ Đường chất vấn tư cách của Hứa Mộc, Trịnh gia tiếp nối các gia tộc khác công khai tuyên bố tiến cử Hứa Mộc. Sự xuất hiện của Trịnh gia góp phần tạo hậu thuẫn chính trị cho Hứa Mộc trong cuộc tranh đoạt.","nguon":["@c0807"]},{"id":"mieu-gia","name":"Miêu gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"chủ tinh","nhanVatChinh":["Người phụ nữ mặc y phục sặc sỡ thuộc chi chính Miêu gia"],"blurb":"Gia tộc trên chủ tinh có người thuộc chi chính đứng ra tiến cử Hứa Mộc. Miêu gia tự khẳng định mình có tư cách tham gia việc đề cử trong cuộc phong danh hiệu.","detail":"Trong làn sóng các gia tộc từng chịu ơn Vương Lâm ở Lôi Tiên Giới, một phụ nữ mặc y phục sặc sỡ thuộc chi chính Miêu gia bước ra tiến cử Hứa Mộc. Việc gia tộc trên chủ tinh này lên tiếng khiến áp lực lên Đường gia tăng thêm.","nguon":["@c0808"]},{"id":"manh-gia","name":"Mạnh gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Địa Viêm Tinh","nhanVatChinh":["Tu sĩ Mạnh gia Địa Viêm Tinh"],"blurb":"Gia tộc ở Địa Viêm Tinh có tu sĩ bước ra tiến cử Hứa Mộc. Đại diện Mạnh gia không sợ áp lực từ lão già họ Đường.","detail":"Mạnh gia thuộc Địa Viêm Tinh tham gia nhóm gia tộc công khai tiến cử Hứa Mộc trong cuộc phong danh hiệu. Tu sĩ đại diện gia tộc nhìn thẳng lão già họ Đường và hỏi Mạnh gia có tư cách hay không.","nguon":["@c0808"]},{"id":"bach-ly-gia","name":"Bách Lý gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Lôi Vân Tinh","nhanVatChinh":[],"blurb":"Gia tộc của Lôi Vân Tinh nằm trong nhóm các gia tộc tiến cử Hứa Mộc. Sự xuất hiện của họ góp vào làn sóng đền ơn từ những người từng được cứu ở Lôi Tiên Giới.","detail":"Bách Lý gia được nhắc trong nhóm gia tộc đứng ra tiến cử Hứa Mộc tại cuộc phong danh hiệu. Gia tộc này thuộc Lôi Vân Tinh và là một phần áp lực tập thể khiến Đường gia khó tiếp tục phủ nhận tư cách của Hứa Mộc.","nguon":["@c0808"]},{"id":"tu-khong-gia-toc","name":"Tư Không gia tộc","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Thủy Minh Tinh","nhanVatChinh":[],"blurb":"Gia tộc của Thủy Minh Tinh tham gia tiến cử Hứa Mộc. Họ thuộc nhóm thế lực công khai đứng về phía người từng cứu mình ở Lôi Tiên Giới.","detail":"Tư Không gia tộc được nêu trong danh sách các gia tộc tiến cử Hứa Mộc trong cuộc phong danh hiệu. Việc gia tộc này tham gia cho thấy ảnh hưởng của ân cứu mạng ở Lôi Tiên Giới lan rộng qua nhiều tinh cầu.","nguon":["@c0808"]},{"id":"chu-gia","name":"Chu gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Địa Viêm Tinh","nhanVatChinh":[],"blurb":"Gia tộc của Địa Viêm Tinh cùng Mạnh gia tham gia làn sóng tiến cử Hứa Mộc. Đây là một trong các thế lực góp phần làm Đường gia mất thế chủ động.","detail":"Chu gia thuộc Địa Viêm Tinh được nhắc trong nhóm gia tộc tiến cử Hứa Mộc. Sự hiện diện của họ cùng Mạnh gia cho thấy Địa Viêm Tinh có nhiều gia tộc lên tiếng ủng hộ tư cách của Hứa Mộc.","nguon":["@c0808"]},{"id":"tru-gia","name":"Trữ gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Thiên Lam Tinh","nhanVatChinh":[],"blurb":"Gia tộc trên chủ tinh Thiên Lam Tinh, tham gia tiến cử Hứa Mộc. Trữ gia tự nhận có tư cách trong cuộc phong danh hiệu.","detail":"Trữ gia của Thiên Lam Tinh được nhắc như một gia tộc trên chủ tinh tiến cử Hứa Mộc. Sự tham gia của họ góp phần củng cố thế hợp pháp của Hứa Mộc trước lời chất vấn từ Đường gia.","nguon":["@c0808"]},{"id":"nam-cung-gia","name":"Nam Cung gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"La Thiên Tinh Vực","nhanVatChinh":["Nam Cung Hàn"],"blurb":"Một trong tứ đại gia tộc của La Thiên Tinh Vực, nổi danh với Cửu Khúc Thiên Đao.","detail":"Nam Cung gia được nhắc là gia tộc đứng đầu trong tứ đại gia tộc La Thiên. Ngàn năm trước, một nửa tộc nhân trên tu chân tinh của gia tộc này mất tích bí ẩn, từng khiến Lôi Tiên Điện chú ý nhưng không tìm ra nguyên nhân.","nguon":["@c0809"]},{"id":"gia-toc-tu-chan-tren-dia-viem-tinh","name":"Gia tộc tu chân trên Địa Viêm Tinh","cn":"","type":"gia-toc","typeLabel":"Gia tộc địa phương","diaBan":"Địa Viêm Tinh","nhanVatChinh":["Vương Lâm"],"blurb":"Gia tộc nơi Vương Lâm được an bài tạm trú trong bảy ngày trước khi tới Lôi Tiên Điện.","detail":"Trong thời gian ở lại, Vương Lâm khoanh chân điều hòa nguyên lực để chuẩn bị trạng thái tốt nhất cho trận chiến cuối của cuộc tranh danh tại La Thiên Tinh Vực.","nguon":["@c0811"]},{"id":"hua-gia-o-dong-lam-tinh","name":"Hứa gia ở Đông Lâm Tinh","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Đông Lâm Tinh","nhanVatChinh":["Hứa Đình"],"blurb":"Gia tộc nổi danh ở Đông Lâm Tinh bằng tiếng tăm giết chóc, mỗi đời người nhập thế đều gây thảm họa máu tanh.","detail":"Khi Hứa Đình tự xưng xuất thân từ Hứa gia ở Đông Lâm Tinh, nhiều tu sĩ biến sắc và lùi lại. Danh tiếng của gia tộc này khiến không ít người nghĩ tới việc tránh hoặc bỏ cuộc nếu gặp Hứa Đình trong tranh đoạt.","nguon":["@c0812"]},{"id":"huong-gia-o-dong-lam-tinh","name":"Hướng gia ở Đông Lâm Tinh","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Đông Lâm Tinh","nhanVatChinh":[],"blurb":"Gia tộc tại Đông Lâm Tinh được nhắc để đối chiếu với danh tiếng Hứa gia.","detail":"Trong lời bàn của tu sĩ, Hướng gia ở Đông Lâm Tinh có thể không phải thế lực mạnh nhất xét về tiếng tăm, vì Hứa gia còn nổi danh hơn bởi giết chóc.","nguon":["@c0812"]},{"id":"tay-gia","name":"Tây gia","cn":"","type":"gia-toc","typeLabel":"gia tộc tu chân","diaBan":"La Thiên Tinh Vực","nhanVatChinh":["Tây Tử Phượng","Lão phu nhân Tây gia","Tây Tử Mặc"],"blurb":"Tây gia là gia tộc của Tây Tử Phượng, có lão tổ cùng nàng tới xem tranh phong tiên.","detail":"Trong trận tranh đoạt phong tiên, lão tổ Tây gia cũng có mặt nhưng không đủ tư cách ngồi bồ đoàn; chương nhấn mạnh Tây Tử Phượng thuộc gia tộc này và có biểu ca Tây Tử Mặc là người ưu tú trong tộc.","nguon":["@c0813"]},{"id":"bon-gia-toc-tu-chan-truyen-thua-tu-tien-gioi","name":"Bốn gia tộc tu chân truyền thừa từ tiên giới","cn":"","type":"nhom-the-luc","typeLabel":"nhóm thế lực","diaBan":"La Thiên Tinh Vực","nhanVatChinh":[],"blurb":"Nhóm bốn gia tộc truyền thừa từ tiên giới xuất hiện trong hàng thế lực tới xem tranh đoạt phong tiên.","detail":"Khi trận phong tiên mở ra, bốn gia tộc tu chân truyền thừa từ tiên giới cử lão quái tới dự khán, thuộc nhóm thế lực được xếp cùng các đại gia tộc và Lôi Tiên Điện.","nguon":["@c0813"]},{"id":"hai-gia-toc-tu-chan-thuong-co","name":"Hai gia tộc tu chân thượng cổ","cn":"","type":"nhom-the-luc","typeLabel":"nhóm thế lực","diaBan":"La Thiên Tinh Vực","nhanVatChinh":[],"blurb":"Hai gia tộc tu chân thượng cổ là nhóm thế lực xuất hiện cuối trong các phe đến dự khán tranh phong tiên.","detail":"Chương nêu hai gia tộc tu chân thượng cổ cùng Lôi Tiên Điện và các gia tộc lớn tới xem cuộc tranh đoạt danh hiệu phong tiên tại Lôi Trì.","nguon":["@c0813"]},{"id":"gia-toc-ho-kep-cong-ton","name":"Gia tộc họ kép Công Tôn","cn":"","type":"gia-toc","typeLabel":"gia tộc tu chân","diaBan":"La Thiên Tinh Vực","nhanVatChinh":["Nam tử họ Công Tôn"],"blurb":"Gia tộc họ kép Công Tôn có nam tử áo đen họ Công Tôn xuất hiện trong nhóm lão quái dự khán phong tiên.","detail":"Nam tử họ Công Tôn đại diện cho gia tộc họ kép Công Tôn, ngồi bồ đoàn và bàn luận truyền thuyết Phong Tiên Thạch, Viễn Cổ Tiên Vực.","nguon":["@c0813"]},{"id":"mon-ha-bach-pham","name":"Môn hạ Bạch Phàm","cn":"","type":"su-mon","typeLabel":"Sư môn","diaBan":"Chưa rõ","nhanVatChinh":["Bạch Phàm","Thanh Thủy Tiên Quân","Vương Lâm"],"blurb":"Môn hạ Bạch Phàm được Thanh Thủy dùng làm chuẩn để đánh giá khí thế của Vương Lâm. Lời này đặt Vương Lâm vào mạch liên hệ sư môn với Bạch Phàm qua Thanh Thủy.","detail":"Khi Vương Lâm công khai phản kích La Tố tại Lôi Tiên Điện, Thanh Thủy nhận xét rằng lúc này hắn mới có chút dáng vẻ một môn hạ của sư tôn Bạch Phàm. Thế lực này hiện được nhắc qua quan hệ sư môn và sự công nhận của Thanh Thủy.","nguon":["@c0814"]}]};
